UPDATE courses
SET price = CASE id
    WHEN '30000000-0000-0000-0000-000000000001' THEN 14990.00
    WHEN '30000000-0000-0000-0000-000000000002' THEN 9900.00
    WHEN '30000000-0000-0000-0000-000000000003' THEN 5950.00
    WHEN '30000000-0000-0000-0000-000000000004' THEN 12000.00
    WHEN '30000000-0000-0000-0000-000000000005' THEN 8990.00
    ELSE price
END
WHERE id IN (
    '30000000-0000-0000-0000-000000000001',
    '30000000-0000-0000-0000-000000000002',
    '30000000-0000-0000-0000-000000000003',
    '30000000-0000-0000-0000-000000000004',
    '30000000-0000-0000-0000-000000000005'
) AND price < 1000^^

